#version 430 core

layout(local_size_x = 8, local_size_y = 8) in;

layout(std430, binding = 0) readonly buffer Closest   { uint  closestBiomes[]; };
layout(std430, binding = 1) readonly buffer Weights   { float biomeWeights[];  };
layout(std430, binding = 2) readonly buffer HVNoise   { float hvNoise[];       };
layout(std430, binding = 3) writeonly buffer HeightMap{ float heightMap[];     };

layout(std430, binding = 4) readonly buffer BiomeRoot{ float biomeRoot[];     };
layout(std430, binding = 5) readonly buffer BiomeVar { float biomeVar[];     };

void main() {
    uint x = gl_GlobalInvocationID.x;
    uint y = gl_GlobalInvocationID.y;

    uint columnOffset = y << 4 | x;
    uint base = columnOffset * 4u;

    float blendedRoot = 0.0f;
    float blendedVar  = 0.0f;

    for (int k = 0; k < 4; k++) {
        uint  biomeIdx = closestBiomes[base + uint(k)];
        float weight   = biomeWeights[base + uint(k)];
        blendedRoot += biomeRoot[biomeIdx] * weight;
        blendedVar  += biomeVar[biomeIdx]  * weight;
    }

    heightMap[columnOffset] = blendedRoot + blendedVar * hvNoise[columnOffset];
}
